import org.hibernate.Session;
import org.hibernate.SessionFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import javax.transaction.Transactional;
@Service  //This is a service in Spring Framework which allows @Component scanning to find and wire beans into the context automatically, similar like Autowire annotation for simple classes within an application Context. It's also useful when configuring spring via XML or Java configuration files (annotations are not needed here).
public class java_48202_SessionManager_A08 {  //Creating a service that manages sessions by using Spring’s transaction management features and the Hibernate ORM library to interact with your database, through session factories.   This is similar how @Autowire annotation in simple classes works within an application context for autowiring dependencies from other beans into this bean automatically
    private SessionFactory sessionFactory;  //Session Factory used by hiberate (a part of the Hibernate ORM) to interact with your database, through a Connection Pool and Transactions.   It allows us manage transactions instead manually which is tedious in real world applications due transaction boundary management at service level
    @Autowired     // This means that this instance/bean can be autowire by Spring's Dependency Injection feature so it will get the bean when needed, similar to constructor-based injection but with annotation based. It works for fields and methods in classes too like here used inside service class
    public java_48202_SessionManager_A08(SessionFactory sessionFactory) {  //constructor where we provide our dependencies (sessionfactory), which hibernate uses while interacting database via connection pool   The DI happens when the object is created not at declaration time, similar to constructor injection. It’s good for managing objects in a more flexible and testable way
        this.sessionFactory = sessionFactory;  //Initializing our fields with injected dependencies (Session Factory) from Spring's Dependency Injection feature   The DI happens when the object is created not at declaration time, similar to constructor injection but here we are using setter based dependency management for better reusability and flexibility
    }    
@Transactional  // This makes our method transaction safe so it can rollback in case of exception or error. It's useful where you want your database operations (like CRUD) be atomic to prevent data corruption when something goes wrong with the operation, similar as a point-of-presence at service level
    public void addSession() {  //Creating our method for adding session using SessionFactory and creating it in transactional way.   The use of 'session' makes sure that operations are managed within this context (i.e., they must be atomic, or no part will fail if another operation is attempted)
        Session session = this.sessionFactory.openSession();  //Opening a new Hibernate "Session" from our pool and getting the Connection associated with it   This allows us to interact directly within that context for database operations (CRUD), instead of going through services or DAOs which is more efficient in real world applications
        session.beginTransaction();    //Starts transaction, similar as a begin block at service level but here inside our Hibernate Session Context  It'll allow us to start manipulating the data within this context (to add entity for instance) and it will be wrapped into an atomic unit which can rollback if any operation fails.
        session.save(/*Your Object*/);   //Perform database operations, here we are saving a new object in our Session Context  Similar to CRUD Operations at service level but within Hibernate's context for example User user = new User(); hibernatesession.persist(user) will be similar
        session.getTransaction().commit(); //This marks transaction as successfully committed, it’ll rollback any changes if something fails before this call and closes the Session to return resources back into connection pool (similar at service level but here inside Hibernate's context for example).   The use of 'session', similar than constructor injection with Spring is very helpful in managing objects within application.
    }  //Creating a method that creates session, adds an object and then commits the transaction which makes sure all data changes are committed to database at once when done or throws exception if something goes wrong while doing it .   This shows how one can interact with Hibernate SessionContext for managing DB operations.
}